import{_ as a}from"./chunks/subs-support-page.Bdji-M7h.js";import{_ as t,o as r,c as s,a0 as i}from"./chunks/framework.jwovEGr5.js";const f=JSON.parse('{"title":"Plans & Tiers","description":"","frontmatter":{},"headers":[],"relativePath":"subscriptions/plans.md","filePath":"subscriptions/plans.md"}'),n={name:"subscriptions/plans.md"};function o(l,e,h,u,m,p){return r(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="plans-tiers" tabindex="-1">Plans &amp; Tiers <a class="header-anchor" href="#plans-tiers" aria-label="Permalink to &quot;Plans &amp; Tiers&quot;">​</a></h1><p>A <strong><a href="./../getting-started/glossary.html#plan">plan</a></strong> sets your limits and unlocks features. There are plans for <strong>kingdoms</strong> and plans for <strong>alliances</strong>, and each comes in a free tier and a premium tier.</p><p><img src="'+a+'" alt="Support &amp; Plans page with plan cards"></p><h2 id="the-free-tier-—-what-you-start-with" tabindex="-1">The free tier — what you start with <a class="header-anchor" href="#the-free-tier-—-what-you-start-with" aria-label="Permalink to &quot;The free tier — what you start with&quot;">​</a></h2><p>Every kingdom and every alliance always has a <strong><a href="./../getting-started/glossary.html#free-tier-fallback-plan">free tier</a></strong>, automatically, from the moment it exists. You don&#39;t request it, choose it, or see it listed as an option — it&#39;s simply what applies when nothing premium is active. It&#39;s there quietly in the background so that limits always exist.</p><p>The free tier is generous enough for normal tracking. You only need premium if you bump into limits or want the extra features.</p><blockquote><p>You won&#39;t find &quot;Free Kingdom&quot; or &quot;Free Alliance&quot; in the plan list you can request. Those are internal fallback tiers, not things you sign up for. If you&#39;re on free, that&#39;s the default — there&#39;s nothing to select.</p></blockquote><h2 id="premium-plans-—-what-you-can-request" tabindex="-1">Premium plans — what you can request <a class="header-anchor" href="#premium-plans-—-what-you-can-request" aria-label="Permalink to &quot;Premium plans — what you can request&quot;">​</a></h2><p>The plans you can actually <strong>request</strong> are the premium ones. There are two, matching the two levels of the app:</p><h3 id="premium-alliance" tabindex="-1">Premium Alliance <a class="header-anchor" href="#premium-alliance" aria-label="Permalink to &quot;Premium Alliance&quot;">​</a></h3><p>For a single alliance. Raises that alliance&#39;s limits and unlocks the alliance-focused premium features — including analytics that follow a player across events and recommendation tools. Best when one alliance wants more room and better insights for itself.</p><h3 id="premium-kingdom" tabindex="-1">Premium Kingdom <a class="header-anchor" href="#premium-kingdom" aria-label="Permalink to &quot;Premium Kingdom&quot;">​</a></h3><p>For a whole kingdom. Raises the kingdom&#39;s limits, unlocks kingdom-level premium features, and — importantly — lets the King <strong><a href="./../getting-started/glossary.html#grant">grant</a></strong> premium to alliances inside the kingdom. Best when a King wants to lift the whole kingdom and share premium with several alliances.</p><blockquote><p>A Supreme Admin can create additional custom plans beyond these two. If your platform offers others, they&#39;ll appear in the request list with their own limits and features. The two above are the standard premium plans that ship with the app.</p></blockquote><h2 id="what-a-plan-actually-contains" tabindex="-1">What a plan actually contains <a class="header-anchor" href="#what-a-plan-actually-contains" aria-label="Permalink to &quot;What a plan actually contains&quot;">​</a></h2><p>Whatever the tier, a plan is made of:</p><ul><li><strong>Limits</strong> (<a href="./../getting-started/glossary.html#quota--limit">quotas</a>) for each kind of resource — players, alliances, events, event instances, results, screenshots, storage space, imports, users, and (for kingdom plans) how many alliances the King can grant to.</li><li><strong>Premium features</strong> — the extras it switches on (see <a href="./premium-features.html">Premium Features</a>).</li></ul><p>Premium plans have higher limits and more features than the free tier. The exact numbers can differ between platforms, so the reliable way to see <em>your</em> limits is your <strong>Subscription &amp; Usage panel</strong> — it always shows your real ceilings, not a generic list.</p><h2 id="about-prices" tabindex="-1">About prices <a class="header-anchor" href="#about-prices" aria-label="Permalink to &quot;About prices&quot;">​</a></h2><p>Plans may show pricing information, but <strong>the app does not process payments</strong>. There is no checkout, card entry, or automatic billing. Any payment is arranged manually with a Supreme Admin — see <a href="./payment-instructions.html">Payment Instructions</a>.</p><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="./effective-plan.html">Which Plan Applies to You</a> — how the app decides your <strong>effective plan</strong> when more than one could apply.</li><li><a href="./premium-features.html">Premium Features</a> — the full list of what premium unlocks.</li><li><a href="./request-subscription.html">Request a Subscription</a> — how to ask for a premium plan.</li></ul>',22)])])}const g=t(n,[["render",o]]);export{f as __pageData,g as default};
